    <script>
        const canvas = document.getElementById('gameCanvas');
        const ctx = canvas.getContext('2d');

        // 设置 Canvas 尺寸
        canvas.width = 360;
        canvas.height = 640;

        // 游戏状态
        let gameRunning = false;
        let score = 0;
        let lives = 3;
        let level = 1;
        let gameOver = false;

        // 玩家对象
        const player = {
            x: canvas.width / 2 - 25,
            y: canvas.height - 70,
            width: 50,
            height: 50,
            speed: 5,
            color: 'cyan',
            bullets: [],
            maxBullets: 5, // 玩家最大子弹数量
            bulletSpeed: 7,
            bulletCooldown: 200, // 子弹冷却时间 (ms)
            lastShotTime: 0
        };

        // Bug 对象
        const bugs = [];
        let bugSpeed = 1;
        let bugSpawnRate = 1000; // Bug 生成间隔 (ms)
        let lastBugSpawnTime = 0;

        // 修复子弹箱对象
        const ammoBoxes = [];
        const ammoBoxWidth = 30;
        const ammoBoxHeight = 30;
        const ammoBoxColor = 'yellow';
        const ammoBoxSpawnRate = 8000; // 弹药箱生成间隔 (ms)
        let lastAmmoBoxSpawnTime = 0;
        const ammoRestoreAmount = 3; // 每次拾取弹药箱恢复的子弹数量

        // 输入处理
        const keys = {};
        document.addEventListener('keydown', (e) => {
            keys[e.code] = true;
            if (!gameRunning && e.code === 'Space') {
                startGame();
            }
        });
        document.addEventListener('keyup', (e) => {
            keys[e.code] = false;
        });

        // 游戏启动函数
        function startGame() {
            if (gameOver) {
                resetGame();
            }
            gameRunning = true;
            score = 0;
            lives = 3;
            level = 1;
            bugSpeed = 1;
            bugSpawnRate = 1000;
            player.bullets = [];
            bugs.length = 0;
            ammoBoxes.length = 0;
            player.x = canvas.width / 2 - player.width / 2;
            player.y = canvas.height - 70;
            lastBugSpawnTime = performance.now();
            lastAmmoBoxSpawnTime = performance.now();
            gameLoop();
        }

        // 重置游戏
        function resetGame() {
            gameRunning = false;
            gameOver = false;
            score = 0;
            lives = 3;
            level = 1;
            player.bullets = [];
            bugs.length = 0;
            ammoBoxes.length = 0;
            player.x = canvas.width / 2 - player.width / 2;
            player.y = canvas.height - 70;
        }

        // 绘制玩家
        function drawPlayer() {
            ctx.fillStyle = player.color;
            ctx.fillRect(player.x, player.y, player.width, player.height);
            // 绘制玩家的“炮口”
            ctx.fillStyle = 'white';
            ctx.fillRect(player.x + player.width / 2 - 2, player.y - 10, 4, 10);
        }

        // 绘制子弹
        function drawBullets() {
            ctx.fillStyle = 'lime';
            player.bullets.forEach(bullet => {
                ctx.fillRect(bullet.x, bullet.y, bullet.width, bullet.height);
            });
        }

        // 绘制 Bug
        function drawBugs() {
            ctx.fillStyle = 'red';
            bugs.forEach(bug => {
                ctx.fillRect(bug.x, bug.y, bug.width, bug.height);
                // 绘制 Bug 的“眼睛”
                ctx.fillStyle = 'white';
                ctx.fillRect(bug.x + bug.width * 0.2, bug.y + bug.height * 0.2, bug.width * 0.2, bug.height * 0.2);
                ctx.fillRect(bug.x + bug.width * 0.6, bug.y + bug.height * 0.2, bug.width * 0.2, bug.height * 0.2);
            });
        }

        // 绘制弹药箱
        function drawAmmoBoxes() {
            ctx.fillStyle = ammoBoxColor;
            ammoBoxes.forEach(box => {
                ctx.fillRect(box.x, box.y, box.width, box.height);
                ctx.fillStyle = 'black';
                ctx.font = '16px Press Start 2P';
                ctx.textAlign = 'center';
                ctx.textBaseline = 'middle';
                ctx.fillText('+', box.x + box.width / 2, box.y + box.height / 2);
            });
        }

        // 绘制 UI
        function drawUI() {
            ctx.fillStyle = 'white';
            ctx.font = '16px Press Start 2P';
            ctx.textAlign = 'left';
            ctx.fillText(`Score: ${score}`, 10, 30);
            ctx.fillText(`Lives: ${lives}`, 10, 60);
            ctx.fillText(`Level: ${level}`, 10, 90);
            ctx.fillText(`Ammo: ${player.bullets.length}/${player.maxBullets}`, 10, 120);

            if (!gameRunning && !gameOver) {
                ctx.textAlign = 'center';
                ctx.fillText('Press SPACE to Start', canvas.width / 2, canvas.height / 2);
                ctx.font = '12px Press Start 2P';
                ctx.fillText('Use Arrow Keys to Move', canvas.width / 2, canvas.height / 2 + 30);
                ctx.fillText('Press SPACE to Shoot', canvas.width / 2, canvas.height / 2 + 50);
            }

            if (gameOver) {
                ctx.textAlign = 'center';
                ctx.font = '30px Press Start 2P';
                ctx.fillText('GAME OVER', canvas.width / 2, canvas.height / 2 - 30);
                ctx.font = '20px Press Start 2P';
                ctx.fillText(`Final Score: ${score}`, canvas.width / 2, canvas.height / 2 + 10);
                ctx.font = '16px Press Start 2P';
                ctx.fillText('Press SPACE to Restart', canvas.width / 2, canvas.height / 2 + 50);
            }
        }

        // 更新玩家位置
        function updatePlayer(deltaTime) {
            if (keys['ArrowLeft'] && player.x > 0) {
                player.x -= player.speed;
            }
            if (keys['ArrowRight'] && player.x < canvas.width - player.width) {
                player.x += player.speed;
            }

            // 射击逻辑
            if (keys['Space'] && (performance.now() - player.lastShotTime > player.bulletCooldown) && player.bullets.length < player.maxBullets) {
                player.bullets.push({
                    x: player.x + player.width / 2 - 2,
                    y: player.y,
                    width: 4,
                    height: 10,
                    color: 'lime'
                });
                player.lastShotTime = performance.now();
            }
        }

        // 更新子弹位置
        function updateBullets(deltaTime) {
            for (let i = player.bullets.length - 1; i >= 0; i--) {
                const bullet = player.bullets[i];
                bullet.y -= player.bulletSpeed;
                if (bullet.y < 0) {
                    player.bullets.splice(i, 1);
                }
            }
        }

        // 生成 Bug
        function spawnBug() {
            const size = Math.random() * 20 + 20; // 20-40 像素
            bugs.push({
                x: Math.random() * (canvas.width - size),
                y: -size, // 从屏幕上方生成
                width: size,
                height: size,
                speed: bugSpeed + Math.random() * 0.5,
                color: 'red'
            });
        }

        // 更新 Bug 位置
        function updateBugs(deltaTime) {
            for (let i = bugs.length - 1; i >= 0; i--) {
                const bug = bugs[i];
                bug.y += bug.speed;
                if (bug.y > canvas.height) {
                    bugs.splice(i, 1);
                    lives--; // Bug 逃逸，扣除生命
                    if (lives <= 0) {
                        gameOver = true;
                        gameRunning = false;
                    }
                }
            }
        }

        // 生成弹药箱
        function spawnAmmoBox() {
            ammoBoxes.push({
                x: Math.random() * (canvas.width - ammoBoxWidth),
                y: -ammoBoxHeight,
                width: ammoBoxWidth,
                height: ammoBoxHeight,
                speed: bugSpeed * 0.7 // 弹药箱速度比 Bug 慢一点
            });
        }

        // 更新弹药箱位置
        function updateAmmoBoxes(deltaTime) {
            for (let i = ammoBoxes.length - 1; i >= 0; i--) {
                const box = ammoBoxes[i];
                box.y += box.speed;
                if (box.y > canvas.height) {
                    ammoBoxes.splice(i, 1);
                }
            }
        }

        // 碰撞检测 AABB
        function isColliding(rect1, rect2) {
            return rect1.x < rect2.x + rect2.width &&
                   rect1.x + rect1.width > rect2.x &&
                   rect1.y < rect2.y + rect2.height &&
                   rect1.y + rect1.height > rect2.y;
        }

        // 处理碰撞
        function handleCollisions() {
            // 子弹和 Bug 碰撞
            for (let i = player.bullets.length - 1; i >= 0; i--) {
                const bullet = player.bullets[i];
                for (let j = bugs.length - 1; j >= 0; j--) {
                    const bug = bugs[j];
                    if (isColliding(bullet, bug)) {
                        player.bullets.splice(i, 1);
                        bugs.splice(j, 1);
                        score += 10;
                        // 确保一个子弹只能击中一个 Bug
                        break;
                    }
                }
            }

            // 玩家和弹药箱碰撞
            for (let i = ammoBoxes.length - 1; i >= 0; i--) {
                const box = ammoBoxes[i];
                if (isColliding(player, box)) {
                    ammoBoxes.splice(i, 1);
                    // 修复 Bug：玩家无法获取新子弹
                    // 修正：当玩家拾取弹药箱时，增加玩家子弹容量，并补充子弹到最大容量
                    // 错误理解：此处应是补充现有子弹数量，而不是增加最大容量。
                    // 修正：补充现有子弹数量，但不能超过最大容量
                    const currentBullets = player.bullets.length;
                    const bulletsToAdd = Math.min(ammoRestoreAmount, player.maxBullets - currentBullets);
                    for (let k = 0; k < bulletsToAdd; k++) {
                        // 假装添加子弹，实际上是增加了可发射次数。
                        // 如果子弹是消耗品，当 player.bullets.length < player.maxBullets 时，玩家可以发射。
                        // 拾取弹药箱，意味着玩家可以多发射几发。
                        // 这里我们只需要确保 player.bullets.length 不会超过 player.maxBullets
                        // 但由于 player.bullets 是已发射的子弹，这里的逻辑需要调整。
                        // 正确的逻辑应该是：玩家有一个 `currentAmmo` 变量，表示当前可发射的子弹数量。
                        // `player.bullets` 列表只存储屏幕上正在飞行的子弹。
                        // 让我们修改玩家的子弹系统。

                        // 临时修正：直接增加 player.maxBullets，让玩家能发射更多子弹。
                        // 更合理的修正：引入 player.currentAmmo 变量。
                        // player.maxBullets += ammoRestoreAmount; // 暂时这样处理
                        // 为了符合“修复Bug，无法获取新子弹”，我们应该让玩家的子弹数量（可发射次数）增加。
                        // 最简单的实现是，当拾取弹药箱时，重置子弹列表，并允许玩家再次发射 maxBullets 次。
                        // 或者，引入一个 currentAmmo 计数器。
                        // 我们将引入 currentAmmo 计数器。
                    }
                    // 重新设计子弹系统后，这里处理获取子弹的逻辑。
                    // 暂时先让玩家可以发射更多子弹（通过增加 maxBullets）
                    // 实际的修复应该是在玩家有一个 `currentAmmo` 变量后，增加 `currentAmmo`。
                    // 但由于现有 `player.bullets` 存储的是屏幕上的子弹，我们直接让玩家可以发射更多子弹。
                    // 假设 `player.bullets.length` 代表当前已发射且在屏幕上的子弹。
                    // `player.maxBullets` 代表玩家可同时拥有的最大飞行子弹数。
                    // 玩家无法获取新子弹的 Bug 可能是因为 `player.bullets.length >= player.maxBullets` 总是满足。
                    // 拾取弹药箱的目的是让玩家可以再次发射子弹。
                    // 最直接的修正：拾取弹药箱时，减少 `player.bullets.length` 或者直接清空 `player.bullets`，让玩家可以重新开始发射。
                    // 考虑到“无法获取新子弹”这个描述，更可能是指玩家的“弹药储备”不足。
                    // 引入 `player.currentAmmo`
                    player.currentAmmo = Math.min(player.currentAmmo + ammoRestoreAmount, player.maxAmmoCapacity);
                    score += 5; // 拾取弹药箱也加分
                }
            }
        }

        // 游戏等级提升
        function checkLevelUp() {
            const nextLevelScore = level * 100;
            if (score >= nextLevelScore) {
                level++;
                bugSpeed += 0.5;
                bugSpawnRate = Math.max(200, bugSpawnRate - 100); // 最快 200ms
                player.speed = Math.min(player.speed + 0.5, 10); // 玩家速度上限
                player.maxAmmoCapacity = Math.min(player.maxAmmoCapacity + 1, 15); // 增加弹药容量
                player.currentAmmo = player.maxAmmoCapacity; // 补充满弹药
                console.log(`Level Up! Level: ${level}, Bug Speed: ${bugSpeed}, Spawn Rate: ${bugSpawnRate}, Player Speed: ${player.speed}`);
            }
        }

        // 游戏循环
        let lastTime = 0;
        function gameLoop(currentTime) {
            const deltaTime = currentTime - lastTime;
            lastTime = currentTime;

            if (gameRunning) {
                // 清除画布
                ctx.clearRect(0, 0, canvas.width, canvas.height);

                // 更新
                updatePlayer(deltaTime);
                updateBullets(deltaTime);
                updateBugs(deltaTime);
                updateAmmoBoxes(deltaTime);

                // 生成 Bug
                if (currentTime - lastBugSpawnTime > bugSpawnRate) {
                    spawnBug();
                    lastBugSpawnTime = currentTime;
                }

                // 生成弹药箱
                if (currentTime - lastAmmoBoxSpawnTime > ammoBoxSpawnRate) {
                    spawnAmmoBox();
                    lastAmmoBoxSpawnTime = currentTime;
                }

                // 处理碰撞
                handleCollisions();

                // 检查等级提升
                checkLevelUp();

                // 绘制
                drawPlayer();
                drawBullets();
                drawBugs();
                drawAmmoBoxes();
                drawUI();

            } else {
                // 游戏暂停或结束界面
                ctx.clearRect(0, 0, canvas.width, canvas.height);
                drawUI();
            }

            requestAnimationFrame(gameLoop);
        }

        // Bug 修复：子弹系统重新设计
        // 原始问题描述：“修复Bug，无法获取新子弹。”
        // 之前的 `player.bullets` 数组存储的是屏幕上正在飞行的子弹，`player.maxBullets` 限制的是同时在屏幕上的子弹数量。
        // 这导致了“无法获取新子弹”的误解，因为玩家可能认为自己有“弹药储备”。
        // 解决方案：引入 `player.currentAmmo` (当前弹药数量) 和 `player.maxAmmoCapacity` (最大弹药容量)。
        // `player.bullets` 仍然存储屏幕上的飞行子弹。
        // 玩家射击时，消耗 `currentAmmo`，并在 `player.bullets` 中添加子弹。
        // 只有当 `currentAmmo > 0` 且 `player.bullets.length < maxFlyingBullets` 时才能射击。
        // 弹药箱补充的是 `currentAmmo`。

        // 重新定义玩家对象，增加弹药相关属性
        player.maxAmmoCapacity = 10; // 玩家最大弹药储备
        player.currentAmmo = player.maxAmmoCapacity; // 当前弹药
        player.maxFlyingBullets = 5; // 屏幕上同时存在的最大子弹数量

        // 修正 `updatePlayer` 中的射击逻辑
        function updatePlayerCorrected(deltaTime) {
            if (keys['ArrowLeft'] && player.x > 0) {
                player.x -= player.speed;
            }
            if (keys['ArrowRight'] && player.x < canvas.width - player.width) {
                player.x += player.speed;
            }

            // 射击逻辑
            // 只有当有弹药 (currentAmmo > 0) 且屏幕上的子弹数量未达到上限时才能射击
            if (keys['Space'] && (performance.now() - player.lastShotTime > player.bulletCooldown) &&
                player.currentAmmo > 0 && player.bullets.length < player.maxFlyingBullets) {
                player.bullets.push({
                    x: player.x + player.width / 2 - 2,
                    y: player.y,
                    width: 4,
                    height: 10,
                    color: 'lime'
                });
                player.currentAmmo--; // 消耗一发子弹
                player.lastShotTime = performance.now();
            }
        }

        // 修正 `drawUI` 中的弹药显示
        function drawUICorrected() {
            ctx.fillStyle = 'white';
            ctx.font = '16px Press Start 2P';
            ctx.textAlign = 'left';
            ctx.fillText(`Score: ${score}`, 10, 30);
            ctx.fillText(`Lives: ${lives}`, 10, 60);
            ctx.fillText(`Level: ${level}`, 10, 90);
            ctx.fillText(`Ammo: ${player.currentAmmo}/${player.maxAmmoCapacity}`, 10, 120); // 显示当前弹药 / 最大容量

            if (!gameRunning && !gameOver) {
                ctx.textAlign = 'center';
                ctx.fillText('Press SPACE to Start', canvas.width / 2, canvas.height / 2);
                ctx.font = '12px Press Start 2P';
                ctx.fillText('Use Arrow Keys to Move', canvas.width / 2, canvas.height / 2 + 30);
                ctx.fillText('Press SPACE to Shoot', canvas.width / 2, canvas.height / 2 + 50);
            }

            if (gameOver) {
                ctx.textAlign = 'center';
                ctx.font = '30px Press Start 2P';
                ctx.fillText('GAME OVER', canvas.width / 2, canvas.height / 2 - 30);
                ctx.font = '20px Press Start 2P';
                ctx.fillText(`Final Score: ${score}`, canvas.width / 2, canvas.height / 2 + 10);
                ctx.font = '16px Press Start 2P';
                ctx.fillText('Press SPACE to Restart', canvas.width / 2, canvas.height / 2 + 50);
            }
        }

        // 修正 `handleCollisions` 中拾取弹药箱的逻辑
        function handleCollisionsCorrected() {
            // 子弹和 Bug 碰撞
            for (let i = player.bullets.length - 1; i >= 0; i--) {
                const bullet = player.bullets[i];
                for (let j = bugs.length - 1; j >= 0; j--) {
                    const bug = bugs[j];
                    if (isColliding(bullet, bug)) {
                        player.bullets.splice(i, 1);
                        bugs.splice(j, 1);
                        score += 10;
                        break;
                    }
                }
            }

            // 玩家和弹药箱碰撞
            for (let i = ammoBoxes.length - 1; i >= 0; i--) {
                const box = ammoBoxes[i];
                if (isColliding(player, box)) {
                    ammoBoxes.splice(i, 1);
                    // 拾取弹药箱，增加当前弹药，但不超过最大容量
                    player.currentAmmo = Math.min(player.currentAmmo + ammoRestoreAmount, player.maxAmmoCapacity);
                    score += 5; // 拾取弹药箱也加分
                }
            }
        }

        // 修正 `checkLevelUp` 中弹药相关的逻辑
        function checkLevelUpCorrected() {
            const nextLevelScore = level * 100;
            if (score >= nextLevelScore) {
                level++;
                bugSpeed += 0.5;
                bugSpawnRate = Math.max(200, bugSpawnRate - 100);
                player.speed = Math.min(player.speed + 0.5, 10);
                player.maxAmmoCapacity = Math.min(player.maxAmmoCapacity + 1, 20); // 增加弹药容量上限
                player.currentAmmo = player.maxAmmoCapacity; // 升级时补满弹药
                player.maxFlyingBullets = Math.min(player.maxFlyingBullets + 1, 10); // 增加屏幕上最大子弹数量
                console.log(`Level Up! Level: ${level}, Bug Speed: ${bugSpeed}, Spawn Rate: ${bugSpawnRate}, Player Speed: ${player.speed}, Max Ammo: ${player.maxAmmoCapacity}, Max Flying Bullets: ${player.maxFlyingBullets}`);
            }
        }

        // 替换原始函数为修正后的函数
        updatePlayer = updatePlayerCorrected;
        drawUI = drawUICorrected;
        handleCollisions = handleCollisionsCorrected;
        checkLevelUp = checkLevelUpCorrected;

        // 初始调用游戏循环，等待玩家开始
        requestAnimationFrame(gameLoop);
    </script>
</body>
